def find_unique_pairs(nums):
    if len(nums) < 2:
        return []
    nums.sort()
    pairs = []
    for i in range(len(nums) - 1):
        if nums[i] != nums[i + 1]:
            pairs.append((nums[i], nums[i + 1]))
    return pairs

def is_balanced_tree(tree):
    def check_balance(node):
        if node is None:
            return 0, True
        left_height, left_balanced = check_balance(node[1])
        right_height, right_balanced = check_balance(node[2])
        balanced = left_balanced and right_balanced and abs(left_height - right_height) <= 1
        return max(left_height, right_height) + 1, balanced
    _, balanced = check_balance(tree)
    return balanced

