#include <stddef.h>

void reverse_string(char *str) {
    if (str == NULL) {
        return;
    }

    char *start = str;
    char *end = str;

    // Find the end of the string
    while (*end != '\0') {
        end++;
    }
    end--;

    // Swap characters from start to end
    while (start < end) {
        char temp = *start;
        *start = *end;
        *end = temp;

        start++;
        end--;
    }
}

