struct Node* reverse_sublist(struct Node* head, int m, int n) {
    if (!head || m == n) return head;

    struct Node *dummy = (struct Node*)malloc(sizeof(struct Node));
    dummy->next = head;
    struct Node *prev = dummy;

    for (int i = 1; i < m; i++) {
        prev = prev->next;
    }

    struct Node *start = prev->next;
    struct Node *then = start->next;

    for (int i = 0; i < n - m; i++) {
        start->next = then->next;
        then->next = prev->next;
        prev->next = then;
        then = start->next;
    }

    head = dummy->next;
    free(dummy);
    return head;
}

