#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 1000

typedef struct {
    char data[MAX_SIZE];
    int top;
} Stack;

void init(Stack* stack) {
    stack->top = -1;
}

int is_empty(Stack* stack) {
    return stack->top == -1;
}

int is_full(Stack* stack) {
    return stack->top == MAX_SIZE - 1;
}

void push(Stack* stack, char value) {
    if (is_full(stack)) {
        exit(1); // Stack overflow
    }
    stack->data[++stack->top] = value;
}

char pop(Stack* stack) {
    if (is_empty(stack)) {
        exit(1); // Stack underflow
    }
    return stack->data[stack->top--];
}

int is_balanced(const char* str) {
    Stack stack;
    init(&stack);

    for (int i = 0; str[i] != '\0'; i++) {
        char ch = str[i];
        if (ch == '(' || ch == '[' || ch == '{') {
            push(&stack, ch);
        } else if (ch == ')' || ch == ']' || ch == '}') {
            if (is_empty(&stack)) {
                return 0;
            }
            char top = pop(&stack);
            if ((ch == ')' && top != '(') ||
                (ch == ']' && top != '[') ||
                (ch == '}' && top != '{')) {
                return 0;
            }
        }
    }

    return is_empty(&stack) ? 1 : 0;
}

