#define INITIAL_CAPACITY 4

typedef struct {
    int* elements;
    size_t size;
    size_t capacity;
} DynamicArray;

void da_init(DynamicArray* da) {
    da->elements = (int*)malloc(INITIAL_CAPACITY * sizeof(int));
    da->size = 0;
    da->capacity = INITIAL_CAPACITY;
}

void da_append(DynamicArray* da, int value) {
    if (da->size >= da->capacity) {
        da->capacity *= 2;
        da->elements = (int*)realloc(da->elements, da->capacity * sizeof(int));
    }
    da->elements[da->size++] = value;
}

int da_get(DynamicArray* da, size_t index) {
    if (index >= da->size) {
        // Handle out of bounds access
        return -1; // Return a special value or handle error
    }
    return da->elements[index];
}

void da_free(DynamicArray* da) {
    free(da->elements);
}

