void reverseLinkedList(struct Node** head) {
    struct Node* prev = NULL;
    struct Node* current = *head;
    struct Node* next = NULL;
    while (current != NULL) {
        next = current->next;
        current->next = prev;
        prev = current;
        current = next;
    }
    *head = prev;
}
```

Complete the task by providing a corrected version of the function and a test suite that verifies the correctness of the solution.

#include <stdlib.h>

struct Node {
    int data;
    struct Node* next;
};

void reverseLinkedList(struct Node** head) {
    struct Node* prev = NULL;
    struct Node* current = *head;
    struct Node* next = NULL;
    while (current != NULL) {
        next = current->next;
        current->next = prev;
        prev = current;
        current = next;
    }
    *head = prev;
}

struct Node* createNode(int data) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

void freeList(struct Node* head) {
    struct Node* temp;
    while (head != NULL) {
        temp = head;
        head = head->next;
        free(temp);
    }
}

tests:
#include <assert.h>

int main() {
    struct Node* head = NULL;
    struct Node* node;

    // Test case 1: Empty list
    reverseLinkedList(&head);
    assert(head == NULL);

    // Test case 2: Single node
    head = createNode(1);
    reverseLinkedList(&head);
    assert(head != NULL);
    assert(head->data == 1);
    assert(head->next == NULL);
    freeList(head);
    head = NULL;

    // Test case 3: Two nodes
    head = createNode(1);
    head->next = createNode(2);
    reverseLinkedList(&head);
    assert(head != NULL);
    assert(head->data == 2);
    assert(head->next != NULL);
    assert(head->next->data == 1);
    assert(head->next->next == NULL);
    freeList(head);
    head = NULL;

    // Test case 4: Three nodes
    head = createNode(1);
    head->next = createNode(2);
    head->next->next = createNode(3);
    reverseLinkedList(&head);
