#include <stdio.h>
#include <string.h>

void reverse(char *start, char *end) {
    while (start < end) {
        char temp = *start;
        *start = *end;
        *end = temp;
        start++;
        end--;
    }
}

void str_reverse_words(char *s) {
    char *word_start = s;
    char *temp = s;

    while (*temp) {
        temp++;
        if (*temp == ' ') {
            reverse(word_start, temp - 1);
            word_start = temp + 1;
        }
    }
    reverse(word_start, temp - 1);
}

